use common::{Error as CommonError, Result as CommonResult, ToCanonicalBytes};
use cryptocore::NodeId;
use std::cmp::Ordering;
use std::time::{SystemTime, UNIX_EPOCH};

/// A Hybrid Logical Clock timestamp.
/// It combines physical time (nanoseconds since UNIX epoch) with a logical counter
/// to ensure a total ordering of events.
#[derive(Clone, Debug, Eq, PartialEq)]
pub struct Hlc {
    /// Nanoseconds since the UNIX_EPOCH.
    timestamp_nanos: u64,
    counter: u16,
    node_id: NodeId,
}

impl Hlc {
    /// Creates a new HLC instance for a specific node, initialized to the current time.
    pub fn new(node_id: NodeId) -> Self {
        let now_nanos = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("System time is before UNIX EPOCH, a critical error.")
            .as_nanos() as u64;

        Self {
            timestamp_nanos: now_nanos,
            counter: 0,
            node_id,
        }
    }

    /// Advances the clock's time, generating a new, unique timestamp.
    pub fn new_timestamp(&mut self) -> Self {
        let physical_nanos = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("System time is before UNIX EPOCH.")
            .as_nanos() as u64;

        if physical_nanos > self.timestamp_nanos {
            self.timestamp_nanos = physical_nanos;
            self.counter = 0;
        } else {
            self.counter = self
                .counter
                .checked_add(1)
                .expect("HLC counter overflow");
        }

        Hlc {
            timestamp_nanos: self.timestamp_nanos,
            counter: self.counter,
            node_id: self.node_id,
        }
    }
}

/// Implement Ord to allow HLCs to be compared, which is their primary purpose.
/// The comparison order is: timestamp -> counter -> node_id.
impl Ord for Hlc {
    fn cmp(&self, other: &Self) -> Ordering {
        self.timestamp_nanos
            .cmp(&other.timestamp_nanos)
            .then_with(|| self.counter.cmp(&other.counter))
            .then_with(|| self.node_id.as_bytes().cmp(other.node_id.as_bytes()))
    }
}

impl PartialOrd for Hlc {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

/// Implementation of our custom serialization trait.
impl ToCanonicalBytes for Hlc {
    fn to_canonical_bytes(&self) -> CommonResult<Vec<u8>> {
        let mut bytes = Vec::new();
        // Use big-endian format to ensure byte representation is machine-independent.
        bytes.extend_from_slice(&self.timestamp_nanos.to_be_bytes());
        bytes.extend_from_slice(&self.counter.to_be_bytes());
        bytes.extend_from_slice(self.node_id.as_bytes());
        Ok(bytes)
    }
}

// --- Unit Tests ---
#[cfg(test)]
mod tests {
    use super::*;
    use cryptocore::{CryptoOperations, NodeKeys};
    use std::thread;
    use std::time::Duration;

    #[test]
    fn test_hlc_ordering_same_node() {
        let node_keys = NodeKeys::new();
        let mut hlc = Hlc::new(*node_keys.node_id());

        let t1 = hlc.new_timestamp();
        thread::sleep(Duration::from_micros(10));
        let t2 = hlc.new_timestamp();

        assert!(
            t2 > t1,
            "A later timestamp should be greater than an earlier one."
        );
    }

    #[test]
    fn test_hlc_ordering_different_nodes() {
        let node_a_keys = NodeKeys::new();
        let node_b_keys = NodeKeys::new();

        let mut hlc_a = Hlc::new(*node_a_keys.node_id());
        let mut hlc_b = Hlc::new(*node_b_keys.node_id());

        let t_a = hlc_a.new_timestamp();
        let t_b = hlc_b.new_timestamp();

        assert_ne!(
            t_a, t_b,
            "Timestamps from different nodes should not be equal."
        );
    }

    #[test]
    fn test_counter_increments_on_same_timestamp() {
        let node_keys = NodeKeys::new();
        let mut hlc = Hlc::new(*node_keys.node_id());

        let t1 = hlc.new_timestamp();

        hlc.timestamp_nanos = t1.timestamp_nanos;
        hlc.counter = t1.counter;

        let t2 = hlc.new_timestamp();

        assert_eq!(
            t2.timestamp_nanos, t1.timestamp_nanos,
            "Timestamp should not have advanced."
        );
        assert_eq!(
            t2.counter,
            t1.counter + 1,
            "Counter should have incremented."
        );
        assert!(
            t2 > t1,
            "t2 should be logically greater than t1 due to the counter."
        );
    }

    #[test]
    fn test_canonical_bytes_consistency() {
        let node_keys = NodeKeys::new();
        let hlc1 = Hlc::new(*node_keys.node_id());
        let hlc2 = hlc1.clone(); // Identical copy

        let bytes1 = hlc1.to_canonical_bytes().unwrap();
        let bytes2 = hlc2.to_canonical_bytes().unwrap();

        assert_eq!(bytes1, bytes2, "Identical HLCs should produce identical canonical bytes.");
    }
                     }
